import { Link } from "react-router-dom";

import styles from "./Navbar.module.css";

const ProfileDropdown = () => {

    return (

        <div className={styles.dropdown}>

            <Link to="/profile">

                My Profile

            </Link>

            <Link to="/settings">

                Settings

            </Link>

            <button>

                Logout

            </button>

        </div>

    );

};

export default ProfileDropdown;
